+                       if (ftp->f_type == NORMAL)
+                               snprintf(cmd, sizeof(cmd),
+                                       "%s\n\t@${NORMAL_CTFCONVERT}",
+                                       compilewith);
+                       compilewith = cmd;
+               }
                *cp = och;
                if (strlen(ftp->f_objprefix))
                        fprintf(f, "\t%s $S/%s\n\n", compilewith, np);
